     8→	"net/http"
     9→	"regexp"
    10→	"sort"
    11→	"strconv"
    12→	"strings"
    13→	"time"
    14→
    15→	"github.com/grafana/alerting/notify/historian"
    16→	"github.com/grafana/alerting/notify/historian/lokiclient"
    17→	"github.com/grafana/dskit/instrument"
    18→	"github.com/grafana/grafana-app-sdk/logging"
    19→	"github.com/prometheus/client_golang/prometheus"
    20→	"github.com/prometheus/client_golang/prometheus/promauto"
    21→	"go.opentelemetry.io/otel/trace"
    22→
    23→	"github.com/grafana/grafana/apps/alerting/historian/pkg/apis/alertinghistorian/v0alpha1"
    24→	"github.com/grafana/grafana/apps/alerting/historian/pkg/app/config"
    25→	"github.com/grafana/grafana/apps/alerting/historian/pkg/app/logutil"
    26→)
    27→
    28→const (
    29→	LokiClientSpanName = "grafana.apps.alerting.historian.client"
    30→	defaultQueryRange  = 6 * time.Hour
    31→	defaultLimit       = 100
    32→	maxLimit           = 1000
    33→	Namespace          = "grafana"
    34→	Subsystem          = "alerting"
    35→)
    36→
    37→var (
    38→	// ErrInvalidQuery is returned if the query is invalid.
    39→	ErrInvalidQuery = errors.New("invalid query")
    40→
    41→	validLabelKeyRegex = regexp.MustCompile("^[a-zA-Z_][a-zA-Z0-9_]*$")
    42→	validRuleUIDRegex  = regexp.MustCompile(`^[a-zA-Z0-9\-\_]*$`)
    43→)
    44→
    45→type lokiClient interface {
    46→	RangeQuery(ctx context.Context, logQL string, start, end, limit int64) (lokiclient.QueryRes, error)
    47→	MetricsQuery(ctx context.Context, logQL string, ts int64, limit int64) (lokiclient.MetricsQueryRes, error)
    48→}
    49→
    50→type LokiReader struct {
    51→	client lokiClient
    52→	logger logging.Logger
    53→}
    54→
    55→func NewLokiReader(cfg config.LokiConfig, reg prometheus.Registerer, logger logging.Logger, tracer trace.Tracer) *LokiReader {
    56→	duration := instrument.NewHistogramCollector(promauto.With(reg).NewHistogramVec(prometheus.HistogramOpts{
    57→		Namespace: Namespace,
    58→		Subsystem: Subsystem,
    59→		Name:      "notification_history_read_request_duration_seconds",
    60→		Help:      "Histogram of read request durations to the notification history store.",
    61→		Buckets:   instrument.DefBuckets,
    62→	}, instrument.HistogramCollectorBuckets))
    63→
    64→	requester := &http.Client{
    65→		Transport: cfg.Transport,
    66→	}
    67→
    68→	gkLogger := logutil.ToGoKitLogger(logger)
    69→	return &LokiReader{
    70→		client: lokiclient.NewLokiClient(cfg.LokiConfig, requester, nil, duration, gkLogger, tracer, LokiClientSpanName),
    71→		logger: logger,
    72→	}
    73→}
    74→
    75→// Query retrieves notification history from an external Loki instance.
    76→// When query.Type is "counts", it returns aggregated counts via a metrics query.
    77→// Otherwise it returns individual notification entries via a range query.
    78→func (h *LokiReader) Query(ctx context.Context, query Query) (QueryResult, error) {
    79→	logql, err := buildQuery(query)
    80→	if err != nil {
    81→		return QueryResult{}, err
    82→	}
    83→
    84→	now := time.Now().UTC()
    85→	from := now.Add(-defaultQueryRange)
    86→	if query.From != nil {
    87→		from = *query.From
    88→	}
    89→	to := now
    90→	if query.To != nil {
    91→		to = *query.To
    92→	}
    93→
    94→	limit := int64(defaultLimit)
    95→	if query.Limit != nil {
    96→		limit = *query.Limit
    97→	}
    98→
    99→	if limit > maxLimit {
   100→		return QueryResult{}, fmt.Errorf("%w: limit (%d) over maximum allowed (%d)", ErrInvalidQuery, limit, maxLimit)
   101→	}
   102→
   103→	qtype := v0alpha1.CreateNotificationqueryRequestBodyTypeEntries
   104→	if query.Type != nil {
   105→		qtype = *query.Type
   106→	}
   107→
   108→	switch qtype {
   109→	case v0alpha1.CreateNotificationqueryRequestBodyTypeEntries:
   110→		entries, err := h.runQuery(ctx, logql, from, to, limit)
   111→		if err != nil {
   112→			return QueryResult{}, err
   113→		}
   114→
   115→		return QueryResult{Entries: entries}, nil
   116→
   117→	case v0alpha1.CreateNotificationqueryRequestBodyTypeCounts:
   118→		// Default to no grouping (all false).
   119→		groupBy := QueryGroupBy{}
   120→		if query.GroupBy != nil {
   121→			groupBy = *query.GroupBy
   122→		}
   123→		counts, err := h.runMetricsQuery(ctx, logql, from, to, limit, groupBy)
   124→		if err != nil {
   125→			return QueryResult{}, err
   126→		}
   127→
   128→		return QueryResult{Counts: counts}, nil
   129→
   130→	default:
   131→		return QueryResult{}, fmt.Errorf("%w: unknown query type (%s)", ErrInvalidQuery, string(qtype))
   132→	}
   133→}
   134→
   135→// QueryAlerts retrieves individual alert entries from an external Loki instance.
   136→func (h *LokiReader) QueryAlerts(ctx context.Context, query AlertQuery) (AlertQueryResult, error) {
   137→	logql, err := buildAlertQuery(query)
   138→	if err != nil {
   139→		return AlertQueryResult{}, err
   140→	}
   141→
   142→	now := time.Now().UTC()
   143→	from := now.Add(-defaultQueryRange)
   144→	if query.From != nil {
   145→		from = *query.From
   146→	}
   147→	to := now
   148→	if query.To != nil {
   149→		to = *query.To
   150→	}
   151→
   152→	limit := int64(defaultLimit)
   153→	if query.Limit != nil {
   154→		limit = *query.Limit
   155→	}
   156→
   157→	if limit > maxLimit {
   158→		return AlertQueryResult{}, fmt.Errorf("%w: limit (%d) over maximum allowed (%d)", ErrInvalidQuery, limit, maxLimit)
   159→	}
   160→
   161→	alerts, err := h.runAlertQuery(ctx, logql, from, to, limit)
   162→	if err != nil {
   163→		return AlertQueryResult{}, err
   164→	}
   165→
   166→	// Prune alerts to the requested limit.
   167→	if int64(len(alerts)) > limit {
   168→		alerts = alerts[:limit]
   169→	}
   170→
   171→	return AlertQueryResult{
   172→		Alerts: alerts,
   173→	}, nil
   174→}
   175→
   176→// buildMetricsQuery constructs the LogQL metrics query that wraps a log filter in a
   177→// topk(sum(count_over_time(...))) aggregation.
   178→func buildMetricsQuery(logqlInner string, from, to time.Time, limit int64, groupBy QueryGroupBy) string {
   179→	// Additional expressions for the inner query if needed.
   180→	logqlInnerExtra := ""
   181→
   182→	// If grouping by outcome, create a field based on whether error is empty.
   183→	if groupBy.Outcome {
   184→		logqlInnerExtra += ` | label_format outcome="{{ if .error }}error{{ else }}success{{ end }}"`
   185→	}
   186→
   187→	// Optionally add the grouping, if any.
   188→	var labels []string
   189→	if groupBy.Receiver {
   190→		labels = append(labels, "receiver")
   191→	}
   192→	if groupBy.Integration {
   193→		labels = append(labels, "integration")
   194→	}
   195→	if groupBy.IntegrationIndex {
   196→		labels = append(labels, "integrationIdx")
   197→	}
   198→	if groupBy.Status {
   199→		labels = append(labels, "status")
   200→	}
   201→	if groupBy.Outcome {
   202→		labels = append(labels, "outcome")
   203→	}
   204→	if groupBy.Error {
   205→		labels = append(labels, "error")
   206→	}
   207→	sumBy := ""
   208→	if len(labels) > 0 {
   209→		sumBy = fmt.Sprintf(" by (%s) ", strings.Join(labels, ","))
   210→	}
   211→
   212→	rangeSeconds := int64(to.Sub(from).Seconds())
   213→	return fmt.Sprintf(`topk(%d, sum%s(count_over_time(%s%s[%ds])))`,
   214→		limit, sumBy, logqlInner, logqlInnerExtra, rangeSeconds)
   215→}
   216→
   217→// runMetricsQuery executes a sum(count_over_time(...)) instant query against Loki and
   218→// converts the metric samples into Count values.
   219→func (h *LokiReader) runMetricsQuery(ctx context.Context, logqlInner string, from, to time.Time, limit int64, groupBy QueryGroupBy) ([]Count, error) {
   220→	logql := buildMetricsQuery(logqlInner, from, to, limit, groupBy)
   221→
   222→	res, err := h.client.MetricsQuery(ctx, logql, to.UnixNano(), limit)
   223→	if err != nil {
   224→		return nil, fmt.Errorf("loki metrics query: %w", err)
   225→	}
   226→
   227→	counts := make([]Count, 0, len(res.Data.Result))
   228→	for _, sample := range res.Data.Result {
   229→		count, err := parseCount(sample)
   230→		if err != nil {
   231→			h.logger.Warn("Ignoring metric sample", "err", err)
   232→			continue
   233→		}
   234→		counts = append(counts, count)
   235→	}
   236→
   237→	// Sort counts by count (highest first).
   238→	sort.Slice(counts, func(i, j int) bool {
   239→		return counts[i].Count > counts[j].Count
   240→	})
   241→
   242→	return counts, nil
   243→}
   244→
   245→// parseCount converts a single Loki MetricSample into a Count.
   246→func parseCount(sample lokiclient.MetricSample) (Count, error) {
   247→	countStr, err := sample.Value.Value()
   248→	if err != nil {
   249→		return Count{}, fmt.Errorf("unparseable value: %w", err)
   250→	}
   251→	count, err := strconv.ParseInt(countStr, 10, 64)
   252→	if err != nil {
   253→		return Count{}, fmt.Errorf("non-integer count %q: %w", countStr, err)
   254→	}
   255→
   256→	entry := Count{Count: count}
   257→	m := sample.Metric
   258→	if v, ok := m["receiver"]; ok {
   259→		entry.Receiver = &v
   260→	}
   261→	if v, ok := m["integration"]; ok {
   262→		entry.Integration = &v
   263→	}
   264→	if v, ok := m["integrationIdx"]; ok {
   265→		i, err := strconv.ParseInt(v, 10, 64)
   266→		if err != nil {
   267→			return Count{}, fmt.Errorf("non-integer integrationIdx %q: %w", v, err)
   268→		}
   269→		entry.IntegrationIndex = &i
   270→	}
   271→	if v, ok := m["status"]; ok {
   272→		s := Status(v)
   273→		entry.Status = &s
   274→	}
   275→	if v, ok := m["outcome"]; ok {
   276→		o := Outcome(v)
   277→		entry.Outcome = &o
   278→	}
   279→	if v, ok := m["error"]; ok {
   280→		entry.Error = &v
   281→	}
   282→	return entry, nil
   283→}
   284→
   285→// buildAlertQuery creates the LogQL to perform the requested alert query.
   286→func buildAlertQuery(query AlertQuery) (string, error) {
   287→	selectors := []string{
   288→		fmt.Sprintf(`%s=%q`, historian.LabelFrom, historian.LabelFromValueAlerts),
   289→	}
   290→
   291→	logql := fmt.Sprintf(`{%s}`, strings.Join(selectors, `,`))
   292→
   293→	// UUID filtering uses structured metadata.
   294→	if query.Uuid != nil && *query.Uuid != "" {
   295→		logql += fmt.Sprintf(` | uuid = %q`, *query.Uuid)
   296→	}
   297→
   298→	logql += ` | json`
   299→
   300→	return logql, nil
   301→}
   302→
   303→// runAlertQuery runs the query and collects alert results.
   304→func (l *LokiReader) runAlertQuery(ctx context.Context, logql string, from, to time.Time, limit int64) ([]AlertEntry, error) {
   305→	alerts := make([]AlertEntry, 0)
   306→	r, err := l.client.RangeQuery(ctx, logql, from.UnixNano(), to.UnixNano(), limit)
   307→	if err != nil {
   308→		return nil, fmt.Errorf("loki range query: %w", err)
   309→	}
   310→
   311→	for _, stream := range r.Data.Result {
   312→		for _, s := range stream.Values {
   313→			alert, err := parseLokiAlertEntry(s)
   314→			if err != nil {
   315→				l.logger.Warn("Ignoring alert history entry", "err", err)
   316→				continue
   317→			}
   318→			alerts = append(alerts, alert)
   319→		}
   320→	}
   321→
   322→	// Sort entries by timestamp (descending - newest first).
   323→	sort.Slice(alerts, func(i, j int) bool {
   324→		return alerts[i].StartsAt.After(alerts[j].StartsAt)
   325→	})
   326→
   327→	l.logger.Debug("Alert history query complete", "alerts", len(alerts))
   328→
   329→	return alerts, nil
   330→}
   331→
   332→// parseLokiAlertEntry unmarshals the JSON stored in an alert entry.
   333→func parseLokiAlertEntry(s lokiclient.Sample) (AlertEntry, error) {
   334→	var lokiEntry historian.NotificationHistoryLokiEntryAlert
   335→	err := json.Unmarshal([]byte(s.V), &lokiEntry)
   336→	if err != nil {
   337→		return AlertEntry{}, fmt.Errorf("failed to unmarshal alert entry [%s]: %w", s.T, err)
   338→	}
   339→
   340→	if lokiEntry.SchemaVersion != historian.SchemaVersion {
   341→		return AlertEntry{}, fmt.Errorf("unsupported schema version [%s]: %d", s.T, lokiEntry.SchemaVersion)
   342→	}
   343→
   344→	labels := lokiEntry.Labels
   345→	if labels == nil {
   346→		labels = make(map[string]string)
   347→	}
   348→
   349→	annotations := lokiEntry.Annotations
   350→	if annotations == nil {
   351→		annotations = make(map[string]string)
   352→	}
   353→
   354→	return AlertEntry{
   355→		Status:      lokiEntry.Status,
   356→		Labels:      labels,
   357→		Annotations: annotations,
   358→		StartsAt:    lokiEntry.StartsAt,
   359→		EndsAt:      lokiEntry.EndsAt,
   360→		Enrichments: lokiEntry.ExtraData,
   361→	}, nil
   362→}
   363→
   364→// buildQuery creates the LogQL to perform the requested query.
   365→func buildQuery(query Query) (string, error) {
   366→	selectors := []string{
   367→		fmt.Sprintf(`%s=%q`, historian.LabelFrom, historian.LabelFromValue),
   368→	}
   369→
   370→	logql := fmt.Sprintf(`{%s}`, strings.Join(selectors, `,`))
   371→
   372→	// RuleUID filtering can be performed using the comma separated structured metadata fields.
   373→	// We can match the uid exactly by anchoring the match to a comma or start/end.
   374→	if query.RuleUID != nil && *query.RuleUID != "" {
   375→		// Validate the uid close to where it is used to form the query,
   376→		// to reduce the risk of introducing a query injection bug.
   377→		if !validRuleUIDRegex.MatchString(*query.RuleUID) {
   378→			return "", fmt.Errorf("%w: rule uid: %q", ErrInvalidQuery, *query.RuleUID)
   379→		}
   380→		logql += fmt.Sprintf(` | rule_uids =~ "(^|.*,)%s($|,.*)"`, *query.RuleUID)
   381→	}
   382→
   383→	// Receiver filtering can be done entirely using structured metadata fields.
   384→	if query.Receiver != nil && *query.Receiver != "" {
   385→		logql += fmt.Sprintf(` | receiver = %q`, *query.Receiver)
   386→	}
   387→
   388→	logql += ` | json`
   389→
   390→	// Add status filter if specified.
   391→	if query.Status != nil && *query.Status != "" {
   392→		logql += fmt.Sprintf(` | status = %q`, *query.Status)
   393→	}
   394→
   395→	// Add group labels filter if specified.
   396→	if query.GroupLabels != nil {
   397→		for _, matcher := range *query.GroupLabels {
   398→			// Validate the matcher close to where it is used to form the query,
   399→			// to reduce the risk of introducing a query injection bug.
   400→			if !validLabelKeyRegex.MatchString(matcher.Label) {
   401→				return "", fmt.Errorf("%w: group label: %q", ErrInvalidQuery, matcher.Label)
   402→			}
   403→			switch matcher.Type {
   404→			case "=", "!=", "=~", "!~":
   405→			default:
   406→				return "", fmt.Errorf("%w: matcher type: %s", ErrInvalidQuery, matcher.Type)
   407→			}
   408→			logql += fmt.Sprintf(` | groupLabels_%s %s %q`, matcher.Label, matcher.Type, matcher.Value)
   409→		}
   410→	}
   411→
   412→	// Add outcome filter if specified.
   413→	if query.Outcome != nil && *query.Outcome != "" {
   414→		switch *query.Outcome {
   415→		case v0alpha1.CreateNotificationqueryRequestNotificationOutcomeSuccess:
   416→			logql += ` | error = ""`
   417→		case v0alpha1.CreateNotificationqueryRequestNotificationOutcomeError:
   418→			logql += ` | error != ""`
   419→		}
   420→	}
   421→
   422→	return logql, nil
   423→}
   424→
   425→// runQuery runs the query and collects results, grouping alerts into notifications.
   426→func (l *LokiReader) runQuery(ctx context.Context, logql string, from, to time.Time, limit int64) ([]Entry, error) {
   427→	entries := make([]Entry, 0)
   428→	r, err := l.client.RangeQuery(ctx, logql, from.UnixNano(), to.UnixNano(), limit)
   429→	if err != nil {
   430→		return nil, fmt.Errorf("loki range query: %w", err)
   431→	}
   432→
   433→	for _, stream := range r.Data.Result {
   434→		for _, s := range stream.Values {
   435→			entry, err := parseLokiEntry(s)
   436→			if err != nil {
   437→				l.logger.Warn("Ignoring notification history entry", "err", err)
   438→				continue
   439→			}
   440→			entries = append(entries, entry)
   441→		}
   442→	}
   443→
   444→	// Sort entries by timestamp (descending - newest first)
   445→	sort.Slice(entries, func(i, j int) bool {
   446→		return entries[i].Timestamp.After(entries[j].Timestamp)
   447→	})
   448→
   449→	l.logger.Debug("Notification history query complete", "notifications", len(entries))
   450→
   451→	return entries, nil
   452→}
   453→
   454→// parseLokiEntry unmarshals the JSON stored in the entry.
   455→func parseLokiEntry(s lokiclient.Sample) (Entry, error) {
   456→	var lokiEntry historian.NotificationHistoryLokiEntry
   457→	err := json.Unmarshal([]byte(s.V), &lokiEntry)
   458→	if err != nil {
   459→		return Entry{}, fmt.Errorf("failed to unmarshal entry [%s]: %w", s.T, err)
   460→	}
   461→
   462→	if lokiEntry.SchemaVersion != 2 {
   463→		return Entry{}, fmt.Errorf("unsupported schema version [%s]: %d", s.T, lokiEntry.SchemaVersion)
   464→	}
   465→
   466→	outcome := OutcomeSuccess
   467→	var entryError *string
   468→	if lokiEntry.Error != "" {
   469→		outcome = OutcomeError
   470→		entryError = &lokiEntry.Error
   471→	}
   472→
   473→	groupLabels := lokiEntry.GroupLabels
   474→	if groupLabels == nil {
   475→		groupLabels = make(map[string]string)
   476→	}
   477→
   478→	ruleUIDs := lokiEntry.RuleUIDs
   479→	if ruleUIDs == nil {
   480→		ruleUIDs = []string{}
   481→	}
   482→
   483→	return Entry{
   484→		Timestamp:        s.T,
   485→		Uuid:             lokiEntry.UUID,
   486→		Receiver:         lokiEntry.Receiver,
   487→		Integration:      lokiEntry.Integration,
   488→		IntegrationIndex: int64(lokiEntry.IntegrationIdx),
   489→		Status:           Status(lokiEntry.Status),
   490→		Outcome:          outcome,
   491→		GroupKey:         lokiEntry.GroupKey,
   492→		GroupLabels:      groupLabels,
   493→		RuleUIDs:         ruleUIDs,
   494→		AlertCount:       int64(lokiEntry.AlertCount),
   495→		Alerts:           []EntryAlert{},
   496→		Retry:            lokiEntry.Retry,
   497→		Error:            entryError,
   498→		Duration:         lokiEntry.Duration,
   499→		PipelineTime:     lokiEntry.PipelineTime,
   500→	}, nil
   501→}
   502→

